body {
    font-family: Arial, sans-serif;
    background-color: #f0f0f0;
    display: flex;
    justify-content: center;
    align-items: center;
    height: 100vh;
    margin: 0;
}

.container {
    background-color: white;
    padding: 20px;
    border-radius: 10px;
    box-shadow: 0 0 10px rgba(0,0,0,0.1);
    max-width: 600px;
    width: 100%;
    text-align: center;
}

h1 {
    text-align: center;
    color: #333;
}

.subject-buttons {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 20px;
    margin-top: 20px;
}

.btn {
    background-color: #4CAF50;
    color: white;
    border: none;
    padding: 15px;
    border-radius: 5px;
    cursor: pointer;
    font-size: 18px;
    text-decoration: none;
    display: inline-block;
    text-align: center;
}

.btn:hover {
    background-color: #45a049;
}

.btn.correct {
    background-color: #4CAF50;
}

.btn.wrong {
    background-color: #f44336;
}

.hide {
    display: none;
}

#controls {
    text-align: center;
}

body {
    font-family: Arial, sans-serif;
    background-color: #f0f0f0;
    display: flex;
    justify-content: center;
    align-items: center;
    height: 100vh;
    margin: 0;
}

.container {
    background-color: white;
    padding: 40px;
    border-radius: 15px;
    box-shadow: 0 10px 30px rgba(0,0,0,0.15);
    max-width: 700px;
    width: 100%;
    text-align: center;
}

h1 {
    text-align: center;
    color: #2c3e50;
    font-size: 2.5em;
    margin: 10px 0 5px 0;
}

h2 {
    text-align: center;
    color: #27ae60;
    font-size: 1.3em;
    margin: 5px 0;
}

.header {
    margin-bottom: 30px;
    padding-bottom: 20px;
    border-bottom: 3px solid #27ae60;
}

.subtitle {
    text-align: center;
    color: #7f8c8d;
    font-size: 1em;
    margin-top: 15px;
}

.subject-buttons {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 20px;
    margin-top: 20px;
}

.btn {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    border: none;
    padding: 20px;
    border-radius: 8px;
    cursor: pointer;
    font-size: 18px;
    font-weight: bold;
    text-decoration: none;
    display: inline-block;
    text-align: center;
    transition: all 0.3s ease;
    box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
}

.btn:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 12px rgba(0, 0, 0, 0.2);
}

.btn.correct {
    background-color: #4CAF50;
}

.btn.wrong {
    background-color: #f44336;
}

.hide {
    display: none;
}

#controls {
    text-align: center;
}
